class ElasticsearchManager:
    def __init__(self, hosts: List[str] = None):
        if hosts is None:
            hosts = ['http://localhost:9200']
        
        try:
            self.es = Elasticsearch(hosts)
            if self.es.ping():
                logger.info("Successfully connected to Elasticsearch")
            else:
                logger.error("Could not connect to Elasticsearch")
        except Exception as e:
            logger.error(f"Error connecting to Elasticsearch: {e}")
            raise

    def create_index(self, index_name: str, mappings: Dict = None, settings: Dict = None) -> bool:
        try:
            body = {}
            if mappings:
                body['mappings'] = mappings
            if settings:
                body['settings'] = settings
            
            if not self.es.indices.exists(index=index_name):
                self.es.indices.create(index=index_name, body=body)
                logger.info(f"Index '{index_name}' created successfully")
                return True
            else:
                logger.info(f"Index '{index_name}' already exists")
                return False
        except ElasticsearchException as e:
            logger.error(f"Error creating index '{index_name}': {e}")
            return False

    def delete_index(self, index_name: str) -> bool:
        try:
            if self.es.indices.exists(index=index_name):
                self.es.indices.delete(index=index_name)
                logger.info(f"Index '{index_name}' deleted successfully")
                return True
            else:
                logger.warning(f"Index '{index_name}' does not exist")
                return False
        except ElasticsearchException as e:
            logger.error(f"Error deleting index '{index_name}': {e}")
            return False

    def index_document(self, index_name: str, document: Dict, doc_id: str = None) -> Optional[str]:
        try:
            result = self.es.index(index=index_name, id=doc_id, document=document)
            logger.info(f"Document indexed with ID: {result['_id']}")
            return result['_id']
        except ElasticsearchException as e:
            logger.error(f"Error indexing document: {e}")
            return None

    def bulk_index_documents(self, index_name: str, documents: List[Dict]) -> Dict:
        try:
            actions = [
                {
                    "_index": index_name,
                    "_source": doc
                }
                for doc in documents
            ]
            
            success, failed = helpers.bulk(self.es, actions, stats_only=True)
            logger.info(f"Bulk indexing: {success} successful, {failed} failed")
            return {"success": success, "failed": failed}
        except ElasticsearchException as e:
            logger.error(f"Error during bulk indexing: {e}")
            return {"success": 0, "failed": len(documents)}

    def get_document(self, index_name: str, doc_id: str) -> Optional[Dict]:
        try:
            result = self.es.get(index=index_name, id=doc_id)
            return result['_source']
        except ElasticsearchException as e:
            logger.error(f"Error retrieving document: {e}")
            return None

    def update_document(self, index_name: str, doc_id: str, updates: Dict) -> bool:
        try:
            self.es.update(index=index_name, id=doc_id, doc=updates)
            logger.info(f"Document {doc_id} updated successfully")
            return True
        except ElasticsearchException as e:
            logger.error(f"Error updating document: {e}")
            return False

    def delete_document(self, index_name: str, doc_id: str) -> bool:
        try:
            self.es.delete(index=index_name, id=doc_id)
            logger.info(f"Document {doc_id} deleted successfully")
            return True
        except ElasticsearchException as e:
            logger.error(f"Error deleting document: {e}")
            return False

    def search(self, index_name: str, query: Dict, size: int = 10, from_: int = 0) -> Dict:
        try:
            result = self.es.search(index=index_name, query=query, size=size, from_=from_)
            hits = result['hits']['hits']
            total = result['hits']['total']['value']
            
            documents = [hit['_source'] for hit in hits]
            
            return {
                "total": total,
                "documents": documents,
                "raw_hits": hits
            }
        except ElasticsearchException as e:
            logger.error(f"Error searching: {e}")
            return {"total": 0, "documents": [], "raw_hits": []}

    def full_text_search(self, index_name: str, search_text: str, fields: List[str] = None, 
                        size: int = 10, from_: int = 0) -> Dict:
        if fields is None:
            fields = ["*"]
        
        query = {
            "multi_match": {
                "query": search_text,
                "fields": fields,
                "type": "best_fields",
                "fuzziness": "AUTO"
            }
        }
        
        return self.search(index_name, query, size, from_)

    def aggregation_query(self, index_name: str, aggs: Dict, query: Dict = None) -> Dict:
        try:
            body = {"aggs": aggs}
            if query:
                body["query"] = query
            
            result = self.es.search(index=index_name, body=body, size=0)
            return result.get('aggregations', {})
        except ElasticsearchException as e:
            logger.error(f"Error in aggregation query: {e}")
            return {}


class LogManager:
    def __init__(self, es_manager: ElasticsearchManager, index_prefix: str = "logs"):
        self.es_manager = es_manager
        self.index_prefix = index_prefix
        self._setup_log_index()

    def _setup_log_index(self):
        mappings = {
            "properties": {
                "timestamp": {"type": "date"},
                "level": {"type": "keyword"},
                "message": {"type": "text"},
                "service": {"type": "keyword"},
                "host": {"type": "keyword"},
                "user": {"type": "keyword"},
                "tags": {"type": "keyword"},
                "metadata": {"type": "object", "enabled": False}
            }
        }
        
        settings = {
            "number_of_shards": 1,
            "number_of_replicas": 1
        }
        
        index_name = self._get_current_index()
        self.es_manager.create_index(index_name, mappings, settings)

    def _get_current_index(self) -> str:
        date_suffix = datetime.utcnow().strftime("%Y.%m.%d")
        return f"{self.index_prefix}-{date_suffix}"

    def log(self, level: str, message: str, service: str = None, host: str = None, 
            user: str = None, tags: List[str] = None, metadata: Dict = None) -> Optional[str]:
        log_entry = {
            "timestamp": datetime.utcnow().isoformat(),
            "level": level.upper(),
            "message": message
        }
        
        if service:
            log_entry["service"] = service
        if host:
            log_entry["host"] = host
        if user:
            log_entry["user"] = user
        if tags:
            log_entry["tags"] = tags
        if metadata:
            log_entry["metadata"] = metadata
        
        index_name = self._get_current_index()
        return self.es_manager.index_document(index_name, log_entry)

    def info(self, message: str, **kwargs) -> Optional[str]:
        return self.log("INFO", message, **kwargs)

    def warning(self, message: str, **kwargs) -> Optional[str]:
        return self.log("WARNING", message, **kwargs)

    def error(self, message: str, **kwargs) -> Optional[str]:
        return self.log("ERROR", message, **kwargs)

    def debug(self, message: str, **kwargs) -> Optional[str]:
        return self.log("DEBUG", message, **kwargs)

    def search_logs(self, search_text: str = None, level: str = None, service: str = None,
                   start_time: str = None, end_time: str = None, size: int = 100) -> Dict:
        must_clauses = []
        
        if search_text:
            must_clauses.append({
                "match": {
                    "message": {
                        "query": search_text,
                        "fuzziness": "AUTO"
                    }
                }
            })
        
        if level:
            must_clauses.append({"term": {"level": level.upper()}})
        
        if service:
            must_clauses.append({"term": {"service": service}})
        
        if start_time or end_time:
            range_query = {"timestamp": {}}
            if start_time:
                range_query["timestamp"]["gte"] = start_time
            if end_time:
                range_query["timestamp"]["lte"] = end_time
            must_clauses.append({"range": range_query})
        
        query = {"bool": {"must": must_clauses}} if must_clauses else {"match_all": {}}
        
        index_pattern = f"{self.index_prefix}-*"
        return self.es_manager.search(index_pattern, query, size=size)

    def get_log_statistics(self, start_time: str = None, end_time: str = None) -> Dict:
        aggs = {
            "levels": {
                "terms": {"field": "level"}
            },
            "services": {
                "terms": {"field": "service"}
            },
            "logs_over_time": {
                "date_histogram": {
                    "field": "timestamp",
                    "calendar_interval": "hour"
                }
            }
        }
        
        query = None
        if start_time or end_time:
            range_query = {"timestamp": {}}
            if start_time:
                range_query["timestamp"]["gte"] = start_time
            if end_time:
                range_query["timestamp"]["lte"] = end_time
            query = {"range": range_query}
        
        index_pattern = f"{self.index_prefix}-*"
        return self.es_manager.aggregation_query(index_pattern, aggs, query)


class SearchPlatform:
    def __init__(self, es_manager: ElasticsearchManager):
        self.es_manager = es_manager

    def create_search_index(self, index_name: str, fields_mapping: Dict) -> bool:
        mappings = {"properties": fields_mapping}
        settings = {
            "analysis": {
                "analyzer": {
                    "custom_analyzer": {
                        "type": "custom",
                        "tokenizer": "standard",
                        "filter": ["lowercase", "asciifolding"]
                    }
                }
            }
        }
        return self.es_manager.create_index(index_name, mappings, settings)

    def add_documents(self, index_name: str, documents: List[Dict]) -> Dict:
        return self.es_manager.bulk_index_documents(index_name, documents)

    def advanced_search(self, index_name: str, search_params: Dict) -> Dict:
        must_clauses = []
        should_clauses = []
        filter_clauses = []
        
        if "text" in search_params:
            must_clauses.append({
                "multi_match": {
                    "query": search_params["text"],
                    "fields": search_params.get("fields", ["*"]),
                    "fuzziness": search_params.get("fuzziness", "AUTO")
                }
            })
        
        if "exact_matches" in search_params:
            for field, value in search_params["exact_matches"].items():
                filter_clauses.append({"term": {field: value}})
        
        if "range_filters" in search_params:
            for field, range_vals in search_params["range_filters"].items():
                filter_clauses.append({"range": {field: range_vals}})
        
        if "should_match" in search_params:
            for condition in search_params["should_match"]:
                should_clauses.append(condition)
        
        query = {
            "bool": {}
        }
        
        if must_clauses:
            query["bool"]["must"] = must_clauses
        if should_clauses:
            query["bool"]["should"] = should_clauses
        if filter_clauses:
            query["bool"]["filter"] = filter_clauses
        
        size = search_params.get("size", 10)
        from_ = search_params.get("from", 0)
        
        return self.es_manager.search(index_name, query, size, from_)

    def suggest(self, index_name: str, field: str, prefix: str, size: int = 5) -> List[str]:
        try:
            query = {
                "match_phrase_prefix": {
                    field: prefix
                }
            }
            
            result = self.es_manager.search(index_name, query, size=size)
            suggestions = []
            
            for doc in result["documents"]:
                if field in doc:
                    suggestions.append(doc[field])
            
            return list(set(suggestions))
        except Exception as e:
            logger.error(f"Error getting suggestions: {e}")
            return []


